import{_ as l,o as i,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"2010年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2010年/核心总结.md","filePath":"01_letters/2010年/核心总结.md"}'),t={name:"01_letters/2010年/核心总结.md"};function o(h,a,n,u,d,s){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="_2010年巴菲特致股东信核心总结" tabindex="-1">2010年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2010年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2010年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长13%，低于标普500的15.1%</li><li>46年复合年增长率20.2%，累计涨幅490,409%</li><li>连续八年实现承保盈利</li></ul><h2 id="重大投资决策" tabindex="-1">重大投资决策 <a class="header-anchor" href="#重大投资决策" aria-label="Permalink to &quot;重大投资决策&quot;">​</a></h2><h3 id="bnsf铁路收购" tabindex="-1">BNSF铁路收购 <a class="header-anchor" href="#bnsf铁路收购" aria-label="Permalink to &quot;BNSF铁路收购&quot;">​</a></h3><ul><li>完成收购伯灵顿北方圣达菲铁路公司（BNSF）</li><li>正常盈利能力税前增长近40%，税后增长超过30%</li><li>使用220亿美元现金，股本增加6%</li></ul><h3 id="固定收益投资赎回" tabindex="-1">固定收益投资赎回 <a class="header-anchor" href="#固定收益投资赎回" aria-label="Permalink to &quot;固定收益投资赎回&quot;">​</a></h3><ul><li>瑞士再保险、高盛、通用电气优先股被赎回</li><li>总计损失约12亿美元税前收益</li><li>赎回溢价约14亿美元</li></ul><h2 id="业绩亮点" tabindex="-1">业绩亮点 <a class="header-anchor" href="#业绩亮点" aria-label="Permalink to &quot;业绩亮点&quot;">​</a></h2><h3 id="五大非保险业务" tabindex="-1">五大非保险业务 <a class="header-anchor" href="#五大非保险业务" aria-label="Permalink to &quot;五大非保险业务&quot;">​</a></h3><ul><li>BNSF、Iscar、Lubrizol、Marmon、MidAmerican Energy</li><li>合计税前利润超过100亿美元（2011年预期）</li></ul><h3 id="资本支出" tabindex="-1">资本支出 <a class="header-anchor" href="#资本支出" aria-label="Permalink to &quot;资本支出&quot;">​</a></h3><ul><li>2010年投入60亿美元房地产和设备</li><li>90%投放在美国</li><li>2011年计划创纪录的80亿美元资本支出</li></ul><h3 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h3><ul><li>连续八年承保盈利，累计170亿美元</li><li>浮存金从410亿美元增至658亿美元</li></ul><h2 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h2><h3 id="新增投资经理" tabindex="-1">新增投资经理 <a class="header-anchor" href="#新增投资经理" aria-label="Permalink to &quot;新增投资经理&quot;">​</a></h3><ul><li>Todd Combs加入，管理10-30亿美元资金</li><li>薪酬基于相对标普500表现</li></ul><h3 id="主要持股" tabindex="-1">主要持股 <a class="header-anchor" href="#主要持股" aria-label="Permalink to &quot;主要持股&quot;">​</a></h3><ul><li>美国运通、可口可乐、IBM、富国银行</li><li>IBM为新进大额投资</li></ul><h2 id="关键投资理念" tabindex="-1">关键投资理念 <a class="header-anchor" href="#关键投资理念" aria-label="Permalink to &quot;关键投资理念&quot;">​</a></h2><h3 id="关于投资风险" tabindex="-1">关于投资风险 <a class="header-anchor" href="#关于投资风险" aria-label="Permalink to &quot;关于投资风险&quot;">​</a></h3><ul><li>风险不是用beta衡量</li><li>真正的风险是导致购买力损失的概率</li><li>生产性资产优于货币资产和无生产力资产</li></ul><h3 id="投资的三类资产" tabindex="-1">投资的三类资产 <a class="header-anchor" href="#投资的三类资产" aria-label="Permalink to &quot;投资的三类资产&quot;">​</a></h3><ol><li><strong>货币计价资产</strong>：债券、存款等，长期看危险</li><li><strong>无生产力资产</strong>：黄金等，依赖他人以更高价格购买</li><li><strong>生产性资产</strong>：企业、农场、房地产，最佳选择</li></ol><h2 id="企业文化与管理原则" tabindex="-1">企业文化与管理原则 <a class="header-anchor" href="#企业文化与管理原则" aria-label="Permalink to &quot;企业文化与管理原则&quot;">​</a></h2><ul><li>管理者以所有者心态运营</li><li>&quot;招得好，管得少&quot;的管理理念</li><li>董事持有超过30亿美元伯克希尔股票</li><li>总部仅有24人，租金年27万美元</li></ul><h2 id="债务与流动性管理" tabindex="-1">债务与流动性管理 <a class="header-anchor" href="#债务与流动性管理" aria-label="Permalink to &quot;债务与流动性管理&quot;">​</a></h2><ul><li>维持至少200亿美元现金等价物</li><li>不依赖银行信贷额度</li><li>不签订可能要求重大抵押品的合同</li><li>信贷如同氧气，充足时不被注意，缺失时至关重要</li></ul><h2 id="保险公司四大纪律" tabindex="-1">保险公司四大纪律 <a class="header-anchor" href="#保险公司四大纪律" aria-label="Permalink to &quot;保险公司四大纪律&quot;">​</a></h2><ol><li>了解所有风险敞口</li><li>保守评估损失可能性和成本</li><li>设定能产生利润的保费</li><li>无法获得适当保费时愿意放弃</li></ol><h2 id="失误与教训" tabindex="-1">失误与教训 <a class="header-anchor" href="#失误与教训" aria-label="Permalink to &quot;失误与教训&quot;">​</a></h2><ul><li>Energy Future Holdings债券投资错误</li><li>房地产复苏预测错误</li><li>收购中的资本配置失误</li></ul><h2 id="美国经济展望" tabindex="-1">美国经济展望 <a class="header-anchor" href="#美国经济展望" aria-label="Permalink to &quot;美国经济展望&quot;">​</a></h2><ul><li>美国最好的日子还在前方</li><li>资金流向机会所在，美国充满机会</li><li>238年来无人因做空美国获益</li></ul>',35)])])}const q=l(t,[["render",o]]);export{b as __pageData,q as default};
